// Import required libraries
const Web3 = require('web3');
const fs = require('fs');

// Set up Ethereum provider (infura, ganache, or local node)
const provider = new Web3.providers.HttpProvider('https://mainnet.infura.io/v3/YOUR_PROJECT_ID');

// Create a web3 instance with the provider
const web3 = new Web3(provider);

// Load wallet configuration from JSON file
const walletConfig = require('./wallet_config.json');

// Define a function to sign transactions with private keys
function signTransaction(tx) {
    const { privateKeys, addresses } = walletConfig;
    return Promise.all(privateKeys.map((privKey, index) => {
        const senderAddress = addresses[index];
        tx.from = senderAddress;
        return web3.eth.accounts.signTransaction(tx, privKey);
    }));
}

// Define a function to send ETH transactions
async function sendETH(recipient, amount, privateKeys) {
    try {
        const gasPrice = await web3.eth.getGasPrice();
        const tx = {
            from: walletConfig.address,
            to: recipient,
            value: web3.utils.toWei(amount.toString(), 'ether'),
            gas: 21000,
            gasPrice: gasPrice * (web3.utils.toHex(1)),
        };
        const signedTx = await signTransaction(tx);
        const txHash = await web3.eth.sendSignedTransaction(signedTx[0].rawTransaction).send();
        return txHash;
    } catch (error) {
        console.error(error);
    }
}

// Define a function to interact with smart contracts
async function interactWithContract(contractAddress, contractAbi, functionName, params) {
    try {
        const contract = new web3.eth.Contract(contractAbi, contractAddress);
        const result = await contract.methods[functionName](...params).call();
        return result;
    } catch (error) {
        console.error(error);
    }
}

